### Java API Controller

```java
@RestController
@RequestMapping("/api/v1")
public class RideController {

    @PostMapping("/rides")
    public ResponseEntity<RideResponse> requestRide(
            @RequestHeader("Authorization") String token,
            @RequestBody RideRequest request) {
        String riderId = authService.validateToken(token);

        // Validate pickup/dropoff coordinates
        geoValidator.validate(request.getPickup(), request.getDropoff());

        // Calculate fare estimate with surge
        FareEstimate fare = pricingService.estimate(
            request.getPickup(), request.getDropoff(), request.getRideType());

        // Create ride and begin matching
        Ride ride = rideService.create(riderId, request, fare);
        matchingService.findDriverAsync(ride.getId());

        return ResponseEntity.status(HttpStatus.CREATED)
            .body(RideResponse.from(ride));
    }

    @GetMapping("/rides/{rideId}")
    public ResponseEntity<RideResponse> getRideStatus(
            @RequestHeader("Authorization") String token,
            @PathVariable String rideId) {
        String userId = authService.validateToken(token);
        Ride ride = rideService.getRide(rideId, userId);
        return ResponseEntity.ok(RideResponse.from(ride));
    }

    @PostMapping("/rides/{rideId}/cancel")
    public ResponseEntity<CancelResponse> cancelRide(
            @RequestHeader("Authorization") String token,
            @PathVariable String rideId,
            @RequestBody CancelRequest request) {
        String userId = authService.validateToken(token);
        CancelResult result = rideService.cancel(
            rideId, userId, request.getReason());
        return ResponseEntity.ok(CancelResponse.from(result));
    }
}
```

