### Handling State Transitions

```python
class RideStateMachine:
    """Enforce valid state transitions and trigger side effects."""

    TRANSITIONS = {
        "REQUESTED":       {"MATCHING", "CANCELLED"},
        "MATCHING":        {"DRIVER_ASSIGNED", "CANCELLED"},
        "DRIVER_ASSIGNED": {"DRIVER_EN_ROUTE", "CANCELLED"},
        "DRIVER_EN_ROUTE": {"ARRIVED", "CANCELLED"},
        "ARRIVED":         {"IN_TRIP", "CANCELLED"},
        "IN_TRIP":         {"COMPLETED"},
        "COMPLETED":       set(),
        "CANCELLED":       set(),
    }

    def transition(self, ride_id: str, current: str, target: str):
        if target not in self.TRANSITIONS.get(current, set()):
            raise ValueError(f"Invalid transition: {current} -> {target}")

        # Update ride status atomically
        updated = self.db.update_ride_status(
            ride_id, expected_status=current, new_status=target
        )
        if not updated:
            raise ConflictError("Ride status changed concurrently")

        # Trigger side effects
        self._on_transition(ride_id, current, target)

    def _on_transition(self, ride_id, from_state, to_state):
        if to_state == "DRIVER_ASSIGNED":
            self.notification.notify_rider(ride_id, "Driver is on the way!")
        elif to_state == "COMPLETED":
            self.payment.charge(ride_id)
            self.notification.prompt_rating(ride_id)
        elif to_state == "CANCELLED":
            self.payment.process_cancellation_fee(ride_id, from_state)
```

> **Interview Tip:** When designing Uber's APIs, emphasize the **idempotency** of ride requests. A rider's phone might send duplicate requests due to network issues. Use an idempotency key (e.g., `X-Idempotency-Key` header) to ensure the same ride is not created twice. This is a subtle but important detail that shows production experience.

## Session 6: Caching, ETA Calculation & Surge Pricing

```mermaid
graph LR
    subgraph "ETA Calculation"
        SRC[Source] --> G[Road Network Graph]
        G --> DJ[Dijkstra/A*]
        DJ --> RT[+ Real-time Traffic]
        RT --> ML[+ ML Adjustment]
        ML --> ETA[Final ETA]
    end
    subgraph "Surge Pricing"
        DEM[Demand<br>ride requests/zone] --> SP[Surge Calculator]
        SUP[Supply<br>available drivers/zone] --> SP
        SP --> SM[Surge Multiplier]
    end
```

### ETA Calculation

ETA (Estimated Time of Arrival) is one of Uber's most critical features. It must be fast, accurate, and account for real-time conditions.

#### Road Network as a Graph

```python
import heapq

class ETAService:
    """Calculate ETA using road network graph + traffic data."""

    def __init__(self):
        # adjacency list: node -> [(neighbor, distance_m, base_time_s)]
        self.road_graph = {}
        self.traffic_data = {}  # edge -> current_speed_factor

    def calculate_eta(self, origin, destination):
        """A* algorithm with traffic-weighted edges."""
        start = self.snap_to_road(origin)
        end = self.snap_to_road(destination)

        # Priority queue: (estimated_total, current_cost, node, path)
        heap = [(self._heuristic(start, end), 0, start, [])]
        visited = set()

        while heap:
            est_total, cost, node, path = heapq.heappop(heap)

            if node == end:
                return cost  # seconds

            if node in visited:
                continue
            visited.add(node)

            for neighbor, distance, base_time in self.road_graph.get(node, []):
                if neighbor in visited:
                    continue
                # Adjust time based on real-time traffic
                traffic_factor = self.traffic_data.get(
                    (node, neighbor), 1.0)
                actual_time = base_time * traffic_factor
                new_cost = cost + actual_time
                est = new_cost + self._heuristic(neighbor, end)
                heapq.heappush(heap, (est, new_cost, neighbor,
                                       path + [node]))

        return float('inf')  # No route found

    def _heuristic(self, node, goal):
        """Haversine distance / max_speed as admissible heuristic."""
        dist = haversine(node.lat, node.lng, goal.lat, goal.lng)
        max_speed_mps = 30  # ~108 km/h
        return dist * 1000 / max_speed_mps
```

```java
// Java: ETA calculation with A* algorithm
public class ETAService {
    private final RoadGraph graph;
    private final TrafficService trafficService;

    public double calculateETA(Location origin, Location destination) {
        RoadNode start = graph.snapToRoad(origin);
        RoadNode end = graph.snapToRoad(destination);

        PriorityQueue<ETANode> heap = new PriorityQueue<>(
            Comparator.comparingDouble(ETANode::getEstimatedTotal));
        heap.offer(new ETANode(start, 0, heuristic(start, end)));
        Set<RoadNode> visited = new HashSet<>();

        while (!heap.isEmpty()) {
            ETANode current = heap.poll();
            if (current.getNode().equals(end)) {
                return current.getCost(); // seconds
            }
            if (visited.contains(current.getNode())) continue;
            visited.add(current.getNode());

            for (RoadEdge edge : graph.getEdges(current.getNode())) {
                if (visited.contains(edge.getTarget())) continue;
                double trafficFactor = trafficService.getFactor(edge);
                double edgeCost = edge.getBaseTime() * trafficFactor;
                double newCost = current.getCost() + edgeCost;
                heap.offer(new ETANode(edge.getTarget(), newCost,
                    newCost + heuristic(edge.getTarget(), end)));
            }
        }
        return Double.MAX_VALUE;
    }
}
```

