### Surge Pricing

Surge pricing balances supply and demand by increasing prices when demand exceeds supply.

```python
import time

class SurgePricingService:
    """Calculate surge multiplier per geographic zone."""

    def __init__(self):
        self.zone_size_km = 2  # Each zone is ~2km x 2km
        self.min_multiplier = 1.0
        self.max_multiplier = 8.0

    def calculate_surge(self, zone_id: str) -> float:
        # Count ride requests in this zone in last 5 minutes
        demand = self.get_demand(zone_id, window_minutes=5)
        # Count available drivers in this zone
        supply = self.get_supply(zone_id)

        if supply == 0:
            return self.max_multiplier

        # Supply-demand ratio
        ratio = demand / supply

        # Surge curve: piecewise linear
        if ratio <= 1.0:
            return 1.0  # No surge: supply meets demand
        elif ratio <= 2.0:
            return 1.0 + (ratio - 1.0) * 1.0  # 1.0x to 2.0x
        elif ratio <= 3.0:
            return 2.0 + (ratio - 2.0) * 1.5  # 2.0x to 3.5x
        else:
            return min(self.max_multiplier, 3.5 + (ratio - 3.0) * 1.0)

    def get_demand(self, zone_id: str, window_minutes: int = 5) -> int:
        key = f"demand:{zone_id}"
        return self.redis.zcount(
            key,
            time.time() - window_minutes * 60,
            time.time()
        )

    def get_supply(self, zone_id: str) -> int:
        return self.location_service.count_available_drivers_in_zone(zone_id)

    def calculate_fare(self, base_fare_cents: int, distance_km: float,
                       duration_min: float, zone_id: str) -> int:
        surge = self.calculate_surge(zone_id)

        # Fare = base + (per_km * distance) + (per_min * duration)
        fare = (
            base_fare_cents
            + int(150 * distance_km)   # $1.50/km
            + int(25 * duration_min)    # $0.25/min
        )
        surged_fare = int(fare * surge)

        # Apply min/max bounds
        return max(500, min(surged_fare, 50000))  # $5 min, $500 max
```

```java
// Java: Surge pricing calculator
public class SurgePricingService {
    private static final double MAX_MULTIPLIER = 8.0;

    public double calculateSurge(String zoneId) {
        int demand = getDemandCount(zoneId, Duration.ofMinutes(5));
        int supply = getAvailableDriverCount(zoneId);

        if (supply == 0) return MAX_MULTIPLIER;

        double ratio = (double) demand / supply;

        if (ratio <= 1.0) return 1.0;
        if (ratio <= 2.0) return 1.0 + (ratio - 1.0);
        if (ratio <= 3.0) return 2.0 + (ratio - 2.0) * 1.5;
        return Math.min(MAX_MULTIPLIER, 3.5 + (ratio - 3.0));
    }

    public FareEstimate calculateFare(Location pickup, Location dropoff,
                                       String rideType, String zoneId) {
        double surge = calculateSurge(zoneId);
        double distanceKm = etaService.calculateDistance(pickup, dropoff);
        double durationMin = etaService.calculateETA(pickup, dropoff) / 60.0;

        RateCard card = getRateCard(rideType);
        int baseCents = card.getBaseFare()
            + (int)(card.getPerKmRate() * distanceKm)
            + (int)(card.getPerMinRate() * durationMin);

        int surgedCents = (int)(baseCents * surge);
        return new FareEstimate(surgedCents, surge, distanceKm, durationMin);
    }
}
