class UberCacheStrategy:
    def get_eta(self, origin, destination):
        cache_key = (
            f"eta:{self._round_coords(origin)}:"
            f"{self._round_coords(destination)}"
        )
        cached = self.redis.get(cache_key)
        if cached:
            return float(cached)

