### Geographic Partitioning

Uber's data and services are naturally partitioned by geography. A ride in San Francisco never needs data from Mumbai. This enables **cell-based architecture**.

```python
class CellBasedArchitecture:
    """Each city/region operates as an independent cell."""

    def __init__(self):
        self.cells = {
            "us-nyc": {
                "location_service": "ls-nyc.uber.internal",
                "matching_service": "ms-nyc.uber.internal",
                "db_host": "db-nyc-primary.uber.internal",
            },
            "us-sf": {
                "location_service": "ls-sf.uber.internal",
                "matching_service": "ms-sf.uber.internal",
                "db_host": "db-sf-primary.uber.internal",
            },
            "in-blr": {
                "location_service": "ls-blr.uber.internal",
                "matching_service": "ms-blr.uber.internal",
                "db_host": "db-blr-primary.uber.internal",
            },
        }

    def route_request(self, lat: float, lng: float) -> dict:
        """Route request to the correct cell based on coordinates."""
        cell_id = self.geo_to_cell(lat, lng)
        return self.cells[cell_id]

    def geo_to_cell(self, lat: float, lng: float) -> str:
        """Map coordinates to a cell using geo-fencing."""
        for cell_id, boundary in self.cell_boundaries.items():
            if boundary.contains(lat, lng):
                return cell_id
        raise ValueError(f"No cell found for ({lat}, {lng})")
