class AutoScaler:
    """Scale services based on per-city metrics."""

    def calculate_replicas(self, city: str, service: str) -> int:
        metrics = self.get_city_metrics(city)

        if service == "location_service":
            # 1 pod per 5K location updates/sec
            return max(2, metrics.location_qps // 5000 + 1)
        elif service == "matching_service":
            # 1 pod per 50 matches/sec
            return max(2, metrics.match_qps // 50 + 1)
        elif service == "ride_service":
            # 1 pod per 100 active rides
            return max(2, metrics.active_rides // 100 + 1)

    def handle_event_surge(self, city: str, event_type: str):
        """Pre-scale for known events (concerts, sports, holidays)."""
        multiplier = {
            "major_concert": 3.0,
            "sports_game_end": 5.0,
            "new_years_eve": 10.0,
            "normal": 1.0,
        }.get(event_type, 1.0)

        for service in ["location_service", "matching_service",
                        "ride_service"]:
            base = self.calculate_replicas(city, service)
            target = int(base * multiplier)
            self.scale_service(city, service, target)
