#### Payment Service Failure

Payment is the most critical non-real-time service. If it fails, riders might get free rides or drivers might not get paid.

```python
import time

class ResilientPaymentService:
    def charge_ride(self, trip_id: str):
        """Process payment with retry and fallback."""
        trip = self.trip_service.get(trip_id)
        fare = self.calculate_final_fare(trip)

        try:
            # Try primary payment processor (Stripe)
            result = self.stripe.charge(
                trip.rider.payment_method,
                amount_cents=fare,
                idempotency_key=f"trip-{trip_id}"
            )
            self.record_payment(trip_id, result)
        except PaymentDeclinedError:
            # Card declined - try backup payment method
            backup = self.get_backup_payment(trip.rider_id)
            if backup:
                result = self.stripe.charge(
                    backup, fare,
                    idempotency_key=f"trip-{trip_id}-backup")
                self.record_payment(trip_id, result)
            else:
                self.flag_for_manual_review(trip_id, fare)
        except PaymentServiceUnavailable:
            # Payment processor down - queue for later
            self.payment_queue.enqueue({
                "trip_id": trip_id,
                "fare_cents": fare,
                "rider_id": trip.rider_id,
                "retry_count": 0,
                "queued_at": time.time()
            })
            # Still complete the trip - charge later
            self.notify_rider(
                trip.rider_id,
                "Payment will be processed shortly")
