### Safety Features

#### Anomaly Detection

```python
class TripAnomalyDetector:
    """Detect safety-related anomalies during trips."""

    def monitor_trip(self, trip_id: str):
        trip = self.trip_service.get(trip_id)
        driver_location = self.location_service.get_latest(trip.driver_id)

        anomalies = []

        # 1. Route deviation
        expected_route = self.route_service.get_expected(trip_id)
        deviation_km = self._distance_from_route(
            driver_location, expected_route)
        if deviation_km > 2.0:
            anomalies.append("ROUTE_DEVIATION")

        # 2. Unexpected stop (>5 min in non-traffic area)
        if self._is_stopped(trip.driver_id, duration_min=5):
            if not self._is_traffic_area(driver_location):
                anomalies.append("UNEXPECTED_STOP")

        # 3. Trip taking much longer than ETA
        elapsed = time.time() - trip.started_at.timestamp()
        if elapsed > trip.estimated_duration_sec * 2:
            anomalies.append("EXCESSIVE_DURATION")

        # 4. Speed anomaly (too fast or erratic)
        speed = self._get_current_speed(trip.driver_id)
        if speed > 50:  # m/s = 180 km/h
            anomalies.append("EXCESSIVE_SPEED")

        if anomalies:
            self._handle_anomalies(trip_id, anomalies)

    def _handle_anomalies(self, trip_id: str, anomalies: list):
        has_severe = any(a in ["ROUTE_DEVIATION", "EXCESSIVE_SPEED"]
                        for a in anomalies)

        if has_severe:
            # Auto-notify safety team
            self.safety_team.alert(trip_id, anomalies)
            # Send check-in to rider
            self.notification.send_safety_check(trip_id)
        else:
            # Log for review
            self.safety_log.record(trip_id, anomalies)
