class UberDisasterRecovery:
    def handle_cell_failure(self, failed_cell: str):
        """Failover when an entire city cell goes down."""
        # 1. Reroute DNS to backup cell
        self.dns.reroute(
            failed_cell, self.get_backup_cell(failed_cell))

