### WebSocket Message Protocol

Unlike REST APIs, WhatsApp core communication happens over WebSocket frames. Define a binary protocol for efficiency:

```python
# Message protocol over WebSocket
import json
from enum import IntEnum

class MessageType(IntEnum):
    TEXT = 1
    IMAGE = 2
    VIDEO = 3
    ACK = 10
    TYPING = 20
    PRESENCE = 21
    GROUP_EVENT = 30

class ChatProtocol:
    @staticmethod
    def encode_message(msg_type: MessageType, payload: dict) -> bytes:
        body = json.dumps(payload).encode("utf-8")
        header = msg_type.to_bytes(1, "big") + len(body).to_bytes(4, "big")
        return header + body

    @staticmethod
    def send_text(sender_id: str, conversation_id: str, text: str, msg_id: str):
        return ChatProtocol.encode_message(MessageType.TEXT, {
            "id": msg_id,
            "from": sender_id,
            "to": conversation_id,
            "body": text,
            "ts": int(time.time() * 1000)
        })
