public class AckHandler {

    public enum AckType {
        SENT,       // Server received message
        DELIVERED,  // Recipient device received
        READ        // Recipient opened the chat
    }

    public void handleAck(String messageId, String userId, AckType type) {
        // Update message status
        messageStatusStore.update(messageId, userId, type);

        // Notify sender about status change
        Message original = messageStore.get(messageId);
        ConnectionInfo senderConn = registry.lookup(original.getSenderId());

        if (senderConn != null) {
            StatusUpdate update = new StatusUpdate(messageId, type,
                Instant.now());
            gatewayClient.deliver(senderConn.getGatewayId(), update);
        }
    }
