### Group Messaging Protocol

```python
class GroupMessageHandler:
    def handle_group_message(self, sender_id: str, group_id: str, message: dict):
        members = self.group_service.get_members(group_id)

        # Exclude sender from delivery
        recipients = [m for m in members if m != sender_id]

        # For small groups (<256): fan-out on write
        # For large groups (256-1024): fan-out on read
        if len(recipients) <= 256:
            for recipient_id in recipients:
                self.route_message(recipient_id, message)
        else:
            # Store once, each member reads on pull
            self.group_message_store.save(group_id, message)
            # Send lightweight notification to online members
            for recipient_id in recipients:
                self.send_notification(recipient_id, group_id, "new_message")
