### Heartbeat-Based Online Detection

```python
class PresenceService:
    HEARTBEAT_INTERVAL = 30  # seconds
    ONLINE_TTL = 45  # seconds (slightly > heartbeat interval)

    def __init__(self, redis_client):
        self.redis = redis_client

    def heartbeat(self, user_id: str):
        key = f"presence:{user_id}"
        was_offline = not self.redis.exists(key)

        # Set online with TTL -- auto-expires if heartbeat stops
        self.redis.setex(key, self.ONLINE_TTL, "online")

        if was_offline:
            self._publish_status_change(user_id, "online")

    def disconnect(self, user_id: str):
        self.redis.delete(f"presence:{user_id}")
        # Store last seen timestamp
        self.redis.set(f"last_seen:{user_id}", int(time.time()))
        self._publish_status_change(user_id, "offline")

    def get_status(self, user_id: str) -> dict:
        if self.redis.exists(f"presence:{user_id}"):
            return {"status": "online"}
        last_seen = self.redis.get(f"last_seen:{user_id}")
        return {"status": "offline", "last_seen": int(last_seen or 0)}

    def _publish_status_change(self, user_id: str, status: str):
        self.redis.publish("presence_changes",
                          json.dumps({"user_id": user_id, "status": status}))
```

### The Fan-Out Problem

When a user comes online, all their contacts need to be notified. With 500 average contacts per user:

| Approach | Writes per status change | Feasibility |
|----------|------------------------|-------------|
| Push to all contacts | 500 per user | High write load |
| Pull on demand | 0 writes | Higher read latency |
| **Hybrid: push to online contacts only** | **~50 per user** | **Recommended** |

```java
// Java - Selective presence fan-out
public class PresenceFanOut {

    public void notifyContacts(String userId, String status) {
        List<String> contacts = contactService.getContacts(userId);

        // Only notify contacts who are currently online
        // (offline contacts will pull status when they come online)
        for (String contactId : contacts) {
            if (presenceService.isOnline(contactId)) {
                ConnectionInfo conn = registry.lookup(contactId);
                if (conn != null) {
                    gateway.send(conn, new PresenceUpdate(userId, status));
                }
            }
        }
    }
}
```

### Caching Strategy

```python
# Multi-layer caching for WhatsApp
class CacheManager:
    def __init__(self):
        self.local_cache = {}  # L1: in-process (LRU, 10K entries)
        self.redis = RedisCluster()  # L2: distributed cache

    def get_user_profile(self, user_id: str) -> dict:
        # L1: local cache (fastest, ~0.1ms)
        if user_id in self.local_cache:
            return self.local_cache[user_id]

        # L2: Redis (~1ms)
        cached = self.redis.get(f"profile:{user_id}")
        if cached:
            profile = json.loads(cached)
            self.local_cache[user_id] = profile
            return profile

        # L3: Database (~5ms)
        profile = self.db.query_user(user_id)
        self.redis.setex(f"profile:{user_id}", 300, json.dumps(profile))
        self.local_cache[user_id] = profile
        return profile

    def get_group_metadata(self, group_id: str) -> dict:
        key = f"group:{group_id}"
        cached = self.redis.get(key)
        if cached:
            return json.loads(cached)
        group = self.db.query_group(group_id)
        self.redis.setex(key, 600, json.dumps(group))  # 10-min TTL
        return group
