```python
# Connection assignment using consistent hashing
import hashlib
from sortedcontainers import SortedDict

class ConnectionAssigner:
    def __init__(self, gateway_nodes: list):
        self.ring = SortedDict()
        self.replicas = 150  # Virtual nodes per physical node
        for node in gateway_nodes:
            for i in range(self.replicas):
                h = self._hash(f"{node}:{i}")
                self.ring[h] = node

    def assign(self, user_id: str) -> str:
        h = self._hash(user_id)
        idx = self.ring.bisect_left(h)
        if idx >= len(self.ring):
            idx = 0
        return self.ring.values()[idx]

    def _hash(self, key: str) -> int:
        return int(hashlib.md5(key.encode()).hexdigest(), 16)
