### Multi-Layer Caching Strategy

Twitter uses multiple caching layers to handle 600K+ timeline reads/sec:

```python
class TwitterCacheStrategy:
    """
    L1: In-process cache (per server, around 1K hot timelines)
    L2: Redis cluster (pre-computed timelines)
    L3: Manhattan (persistent KV store)
    L4: MySQL (source of truth)
    """

    def get_tweet(self, tweet_id: int):
        # L1: Check in-process cache (Guava/Caffeine)
        tweet = self.local_cache.get(tweet_id)
        if tweet:
            return tweet

        # L2: Check Redis
        tweet = self.redis.get(f"tweet:{tweet_id}")
        if tweet:
            self.local_cache.put(tweet_id, tweet)
            return tweet

        # L3: Check Manhattan
        tweet = self.manhattan.get(f"tweet:{tweet_id}")
        if tweet:
            self.redis.setex(f"tweet:{tweet_id}", 3600, tweet)
            self.local_cache.put(tweet_id, tweet)
            return tweet

        return None
```

| Cache Layer | Latency | Hit Rate | Size | Purpose |
|-------------|---------|----------|------|---------|
| L1: In-process | <1ms | ~40% | 100MB per server | Viral/hot tweets |
| L2: Redis cluster | 1-5ms | ~95% | 1+ TB | Timelines, tweet objects |
| L3: Manhattan | 5-20ms | ~99.9% | 100+ TB | Persistent KV store |
| L4: MySQL | 20-100ms | 100% | Petabytes | Source of truth |

### Tweet Search: Earlybird

Twitter built **Earlybird**, a custom real-time search engine based on Lucene:

```python
# Simplified inverted index for tweet search
class TweetSearchIndex:
    def __init__(self):
        self.inverted_index = {}  # term -> sorted list of (tweet_id, score)
        self.tweet_metadata = {}   # tweet_id -> {user_id, timestamp, engagement}

    def index_tweet(self, tweet_id: int, text: str, user_id: int, timestamp: float):
        tokens = self.tokenize(text)
        for token in tokens:
            if token not in self.inverted_index:
                self.inverted_index[token] = []
            self.inverted_index[token].append((tweet_id, timestamp))
        self.tweet_metadata[tweet_id] = {
            "user_id": user_id, "timestamp": timestamp, "engagement": 0
        }

    def search(self, query: str, count: int = 20):
        tokens = self.tokenize(query)
        # Intersect posting lists
        if not tokens:
            return []
        result_set = set(tid for tid, _ in self.inverted_index.get(tokens[0], []))
        for token in tokens[1:]:
            posting = set(tid for tid, _ in self.inverted_index.get(token, []))
            result_set &= posting

        # Rank by recency + engagement
        results = [(tid, self._score(tid)) for tid in result_set]
        results.sort(key=lambda x: x[1], reverse=True)
        return results[:count]

    def _score(self, tweet_id: int):
        meta = self.tweet_metadata[tweet_id]
        recency = meta["timestamp"]
        engagement = meta["engagement"]
        return recency * 0.7 + engagement * 0.3
```

```java
// Java: Search service with Lucene-style indexing
public class EarlybirdSearchService {
    private final ConcurrentHashMap<String, List<PostingEntry>> invertedIndex;

    public void indexTweet(long tweetId, String text, long userId) {
        List<String> tokens = tokenize(text.toLowerCase());
        for (String token : tokens) {
            invertedIndex.computeIfAbsent(token, k -> new CopyOnWriteArrayList<>())
                .add(new PostingEntry(tweetId, System.currentTimeMillis()));
        }
    }

    public List<Long> search(String query, int count) {
        List<String> tokens = tokenize(query.toLowerCase());
        if (tokens.isEmpty()) return Collections.emptyList();

        // Intersect posting lists
        Set<Long> resultSet = invertedIndex.getOrDefault(tokens.get(0), List.of())
            .stream().map(PostingEntry::getTweetId).collect(Collectors.toSet());

        for (int i = 1; i < tokens.size(); i++) {
            Set<Long> postings = invertedIndex.getOrDefault(tokens.get(i), List.of())
                .stream().map(PostingEntry::getTweetId).collect(Collectors.toSet());
            resultSet.retainAll(postings);
        }

        return resultSet.stream()
            .sorted(Comparator.reverseOrder())
            .limit(count)
            .collect(Collectors.toList());
    }
}
