### Fan-out Service Scaling

The fan-out service is the most compute-intensive component. It must perform ~1.7M Redis writes per second.

```python
from collections import defaultdict

class PartitionedFanOut:
    """Partition fan-out workers by follower_id range."""

    def __init__(self, num_partitions: int = 256):
        self.num_partitions = num_partitions

    def get_partition(self, follower_id: int) -> int:
        return follower_id % self.num_partitions

    def fan_out(self, tweet_id: int, user_id: int, timestamp: float):
        followers = social_graph.get_followers(user_id)

        # Group followers by partition
        partitioned = defaultdict(list)
        for fid in followers:
            partition = self.get_partition(fid)
            partitioned[partition].append(fid)

        # Send to partition-specific Kafka topics
        for partition, follower_ids in partitioned.items():
            kafka.produce(
                topic=f"fanout-partition-{partition}",
                value={"tweet_id": tweet_id, "followers": follower_ids,
                       "timestamp": timestamp}
            )
```

