```python
# Consistent hashing for Redis timeline shards
import hashlib

class TimelineRedisCluster:
    def __init__(self, nodes: list, virtual_nodes: int = 150):
        self.ring = {}
        self.sorted_keys = []
        for node in nodes:
            for i in range(virtual_nodes):
                key = self._hash(f"{node}:{i}")
                self.ring[key] = node
                self.sorted_keys.append(key)
        self.sorted_keys.sort()

    def get_node(self, user_id: int) -> str:
        key = self._hash(str(user_id))
        for ring_key in self.sorted_keys:
            if key <= ring_key:
                return self.ring[ring_key]
        return self.ring[self.sorted_keys[0]]

    def _hash(self, key: str) -> int:
        return int(hashlib.md5(key.encode()).hexdigest(), 16)
```

### Handling Traffic Spikes

Major events (Super Bowl, elections, breaking news) can cause 10x normal traffic:

```python
class TrafficSpikeMitigation:
    """Strategies for handling sudden traffic spikes."""

    def adaptive_fan_out(self, tweet_id, user_id, follower_count):
        """Delay fan-out for viral tweets during spikes."""
        current_qps = self.monitor.get_fan_out_qps()
        max_qps = self.config.max_fan_out_qps

        if current_qps > max_qps * 0.8:
            # Shed load: delay fan-out for low-priority users
            priority = self._calculate_priority(user_id, follower_count)
            if priority < 0.5:
                # Queue for delayed processing
                delayed_queue.add(tweet_id, delay_seconds=30)
                return

        # Normal fan-out
        self.fan_out_service.fan_out(tweet_id, user_id)

    def circuit_breaker(self, service_name: str):
        """Stop calling a failing downstream service."""
        stats = self.stats[service_name]
        error_rate = stats.errors / max(stats.total, 1)

        if error_rate > 0.5:
            # Circuit is OPEN: return cached/degraded response
            return "OPEN"
        elif error_rate > 0.2:
            # HALF-OPEN: send 10% of traffic to test recovery
            return "HALF_OPEN"
        return "CLOSED"
```

### Tweet Storage Partitioning

```python
class TweetPartitioning:
    """Dual-partitioning strategy for tweets."""

    def write_tweet(self, tweet):
        # Primary partition: by user_id (for user timeline queries)
        user_shard = self.get_shard(tweet.user_id)
        user_shard.write(tweet)

        # Secondary index: by time (for search and analytics)
        time_partition = self.get_time_partition(tweet.created_at)
        time_partition.index(tweet)

    def get_shard(self, user_id: int) -> int:
        return user_id % self.num_shards

    def get_time_partition(self, timestamp) -> str:
        # Partition by day for time-range queries
        return timestamp.strftime("%Y-%m-%d")
