```python
class ResilientTimeline:
    def get_timeline(self, user_id: int, count: int = 20):
        """Graceful degradation when components fail."""
        try:
            # Primary: pre-computed timeline from Redis
            return self.redis_cache.get_timeline(user_id, count)
        except RedisConnectionError:
            self.metrics.increment("timeline.cache_miss.redis_down")
            try:
                # Fallback 1: compute on-the-fly from tweet store
                return self._compute_timeline(user_id, count)
            except Exception:
                # Fallback 2: serve stale cached data from local cache
                stale = self.local_cache.get(f"timeline:{user_id}")
                if stale:
                    return stale
                # Fallback 3: show popular/trending tweets
                return self.trending_service.get_popular_tweets(count)
