### Disaster Recovery

```python
class DisasterRecovery:
    """Multi-datacenter architecture for Twitter."""

    DATACENTERS = ["us-east", "us-west", "eu-west"]
    PRIMARY = "us-east"

    def handle_dc_failure(self, failed_dc: str):
        """Failover procedure when a datacenter goes down."""
        if failed_dc == self.PRIMARY:
            # Promote us-west to primary
            new_primary = "us-west"
            self._promote_to_primary(new_primary)
            # Update DNS to route traffic away from failed DC
            self._update_dns(failed_dc, active=False)
            # Trigger alert for on-call
            self.pager.alert(
                f"DC {failed_dc} failed. Promoted {new_primary} to primary.",
                severity="SEV1"
            )

        # Non-primary DC failure: just reroute traffic
        else:
            self._update_dns(failed_dc, active=False)
            self._redistribute_load(failed_dc)

    def _promote_to_primary(self, dc: str):
        # Ensure replication is caught up
        lag = self._get_replication_lag(dc)
        if lag > 60:  # seconds
            self.alert(f"Replication lag is {lag}s - data loss possible")
        # Switch write endpoint
        self.config.set("primary_dc", dc)
