@Component
public class TwitterHealthCheck implements HealthIndicator {

    @Override
    public Health health() {
        Map<String, Status> checks = new HashMap<>();

        checks.put("redis", checkRedis());
        checks.put("manhattan", checkManhattan());
        checks.put("kafka", checkKafka());
        checks.put("search", checkEarlybird());

        boolean allHealthy = checks.values().stream()
            .allMatch(s -> s == Status.UP);

        Health.Builder builder = allHealthy ? Health.up() : Health.down();
        checks.forEach((name, status) ->
            builder.withDetail(name, status.toString()));

        return builder.build();
    }

    private Status checkRedis() {
        try {
            String pong = jedis.ping();
            return "PONG".equals(pong) ? Status.UP : Status.DOWN;
        } catch (Exception e) {
            return Status.DOWN;
        }
    }
}
