def add_tracks_to_playlist(playlist_id):
    body = request.get_json()
    track_uris = body.get("uris", [])
    position = body.get("position")
    snapshot_id = body.get("snapshot_id")

    playlist = playlist_repo.get(playlist_id)
    if not playlist:
        return jsonify({"error": "not_found"}), 404

    if not playlist.is_collaborative and playlist.owner_id != request.user.id:
        return jsonify({"error": "forbidden"}), 403

    # Optimistic concurrency check
    if snapshot_id and playlist.snapshot_id != snapshot_id:
        return jsonify({"error": "conflict", "current_snapshot": playlist.snapshot_id}), 409

    new_snapshot = playlist_service.add_tracks(playlist, track_uris, position)
    return jsonify({"snapshot_id": new_snapshot}), 201
