### Adaptive Quality Switching

```python
class AdaptiveStreamManager:
    QUALITY_LEVELS = [24, 96, 160, 320]  # kbps

    def __init__(self):
        self.current_quality = 160
        self.bandwidth_samples = []
        self.buffer_seconds = 0

    def measure_bandwidth(self, bytes_received, time_elapsed_ms):
        bandwidth_kbps = (bytes_received * 8) / time_elapsed_ms
        self.bandwidth_samples.append(bandwidth_kbps)
        if len(self.bandwidth_samples) > 10:
            self.bandwidth_samples.pop(0)
        return sum(self.bandwidth_samples) / len(self.bandwidth_samples)

    def select_quality(self, avg_bandwidth_kbps):
        # Use 80% of bandwidth to leave headroom
        usable = avg_bandwidth_kbps * 0.8
        selected = self.QUALITY_LEVELS[0]
        for q in self.QUALITY_LEVELS:
            if q <= usable:
                selected = q
        return selected

    def should_switch(self, new_quality):
        if new_quality > self.current_quality:
            return self.buffer_seconds > 10  # upgrade only with healthy buffer
        elif new_quality < self.current_quality:
            return self.buffer_seconds < 5   # downgrade when buffer is low
        return False
```

### Prefetching and Gapless Playback

```python
class PlaybackEngine:
    def __init__(self):
        self.current_track = None
        self.next_track_buffer = None
        self.crossfade_ms = 0

    def on_track_progress(self, position_ms, duration_ms):
        remaining_ms = duration_ms - position_ms
        if remaining_ms < 30_000 and not self.next_track_buffer:
            next_track = self.queue.peek_next()
            if next_track:
                self.prefetch(next_track)

    def prefetch(self, track):
        stream_url = api.get_stream_url(track.id, quality=self.current_quality)
        # Download first 10s worth of data
        bytes_needed = (self.current_quality * 1000 / 8) * 10
        self.next_track_buffer = download_range(stream_url, 0, int(bytes_needed))
        # Pre-decode to PCM for instant playback
        self.next_track_pcm = decode_ogg(self.next_track_buffer)

    def transition_to_next(self):
        if self.crossfade_ms > 0:
            self._crossfade(self.current_track, self.next_track_pcm)
        else:
            # Gapless: start next track PCM the instant current ends
            self.audio_output.enqueue(self.next_track_pcm)
