public class PrefetchManager {
    private final ExecutorService executor = Executors.newSingleThreadExecutor();
    private final Map<UUID, byte[]> prefetchCache = new ConcurrentHashMap<>();

    public void onTrackProgress(UUID currentTrackId, long positionMs, long durationMs) {
        long remainingMs = durationMs - positionMs;
        UUID nextTrackId = playQueue.peekNext();

        if (remainingMs < 30_000 && nextTrackId != null
                && !prefetchCache.containsKey(nextTrackId)) {
            executor.submit(() -> prefetch(nextTrackId));
        }
    }

    private void prefetch(UUID trackId) {
        StreamResponse stream = streamingClient.getStreamUrl(trackId, currentQuality);
        int bytesNeeded = (currentQuality * 1000 / 8) * 10;
        byte[] buffer = httpClient.downloadRange(stream.getUrl(), 0, bytesNeeded);
        prefetchCache.put(trackId, buffer);
    }

    public byte[] getPrefetchedData(UUID trackId) {
        return prefetchCache.remove(trackId);
    }
}
