### Three Pillars of Spotify Recommendations

#### 1. Collaborative Filtering

"Users who listened to X also listened to Y" -- the most powerful signal.

```python
import numpy as np
from scipy.sparse import csr_matrix
from sklearn.decomposition import TruncatedSVD

class CollaborativeFilter:
    def __init__(self, n_factors=128):
        self.n_factors = n_factors
        self.model = TruncatedSVD(n_components=n_factors)

    def build_interaction_matrix(self, play_events):
        user_ids = sorted(set(e.user_id for e in play_events))
        track_ids = sorted(set(e.track_id for e in play_events))
        user_idx = {uid: i for i, uid in enumerate(user_ids)}
        track_idx = {tid: i for i, tid in enumerate(track_ids)}

        rows, cols, vals = [], [], []
        for event in play_events:
            confidence = self._compute_confidence(event)
            rows.append(user_idx[event.user_id])
            cols.append(track_idx[event.track_id])
            vals.append(confidence)

        return csr_matrix((vals, (rows, cols)),
                          shape=(len(user_ids), len(track_ids)))

    def _compute_confidence(self, event):
        completion_ratio = event.duration_played / event.track_duration
        if event.skipped:
            return 0.1  # negative signal
        elif completion_ratio > 0.8:
            return 1.0 + 0.5 * event.play_count  # strong positive
        else:
            return 0.5 * completion_ratio

    def train(self, interaction_matrix):
        self.user_factors = self.model.fit_transform(interaction_matrix)
        self.track_factors = self.model.components_.T

    def recommend(self, user_idx, n=30, exclude_known=True):
        scores = np.dot(self.user_factors[user_idx], self.track_factors.T)
        if exclude_known:
            known = self.interaction_matrix[user_idx].nonzero()[1]
            scores[known] = -np.inf
        top_indices = np.argsort(scores)[-n:][::-1]
        return top_indices
```

#### 2. Content-Based Filtering (NLP on Metadata)

Spotify crawls blogs, reviews, and social media to build **cultural vectors** for tracks.

```python
class ContentBasedFilter:
    def extract_features(self, track):
        return {
            "genre_vector": self.encode_genres(track.genres),
            "artist_vector": self.encode_artist(track.artist),
            "release_recency": self.time_decay(track.release_date),
            "cultural_vector": self.nlp_encode(track.descriptions),
            "popularity_score": track.play_count / self.max_play_count,
        }

    def similarity(self, track_a, track_b):
        fa = self.extract_features(track_a)
        fb = self.extract_features(track_b)
        vec_a = np.concatenate(list(fa.values()))
        vec_b = np.concatenate(list(fb.values()))
        return np.dot(vec_a, vec_b) / (np.linalg.norm(vec_a) * np.linalg.norm(vec_b))
```

