### Discover Weekly Pipeline

```java
// Discover Weekly batch job (runs Sunday night)
public class DiscoverWeeklyJob implements SparkJob {

    @Override
    public void run(SparkSession spark) {
        // Step 1: Load user play history (last 3 months)
        Dataset<PlayEvent> plays = spark.read()
            .format("cassandra")
            .option("table", "play_history")
            .load()
            .filter(col("played_at").gt(threeMonthsAgo()));

        // Step 2: Build collaborative filtering recommendations
        Dataset<Recommendation> cfRecs = collaborativeFilter.recommend(plays, 100);

        // Step 3: Filter out tracks user has already heard
        Dataset<Recommendation> filtered = cfRecs
            .join(plays, cfRecs.col("track_id").equalTo(plays.col("track_id")), "left_anti");

        // Step 4: Diversify (avoid too many tracks from same artist)
        Dataset<Recommendation> diversified = diversify(filtered, 2);

        // Step 5: Select top 30 and write playlist
        Dataset<Recommendation> top30 = diversified.orderBy(col("score").desc()).limit(30);

        // Step 6: Write to playlist service
        top30.foreachPartition(partition -> {
            PlaylistServiceClient client = new PlaylistServiceClient();
            partition.forEachRemaining(rec ->
                client.setDiscoverWeekly(rec.getUserId(), rec.getTrackIds())
            );
        });
    }
}
