class OfflineManager:
    def download_for_offline(self, track_id, user_id):
        if not self.user_service.is_premium(user_id):
            raise PermissionError("Premium required for offline playback")

        audio = self.streaming_service.get_audio(track_id, quality="320")

        # Generate device-specific encryption key
        device_key = self.drm_service.get_device_key(user_id, self.device_id)

        # Encrypt with AES-256-GCM
        encrypted = self.encrypt_aes_gcm(audio.data, device_key)

        self.local_storage.save(
            path=f"offline/{track_id}.enc",
            data=encrypted,
