        )

    def play_offline(self, track_id):
        meta = self.local_storage.get_metadata(f"offline/{track_id}.enc")

        if datetime.fromisoformat(meta["license_expiry"]) < datetime.utcnow():
            raise LicenseExpiredError("Reconnect to internet to refresh license")

        device_key = self.drm_service.get_local_device_key()
        encrypted = self.local_storage.read(f"offline/{track_id}.enc")
        audio = self.decrypt_aes_gcm(encrypted, device_key)
        return audio
