public class CDNFailoverManager {
    private final Map<String, HealthStatus> popHealth = new ConcurrentHashMap<>();

    @Scheduled(fixedRate = 5000)
    public void healthCheck() {
        for (String pop : cdnConfig.getAllPops()) {
            try {
                long latency = httpClient.head(pop + "/health").getLatencyMs();
                popHealth.put(pop, new HealthStatus(true, latency));
            } catch (Exception e) {
                popHealth.put(pop, new HealthStatus(false, -1));
            }
        }
    }

    public String selectPop(String userRegion) {
        List<String> candidates = cdnConfig.getPopsForRegion(userRegion);
        return candidates.stream()
            .filter(pop -> popHealth.getOrDefault(pop, HealthStatus.UNKNOWN).isHealthy())
            .min(Comparator.comparingLong(pop -> popHealth.get(pop).getLatencyMs()))
            .orElse(cdnConfig.getOriginPop());
    }
}
