### Play Count & Royalty Tracking

Every time a user plays a track for at least 30 seconds, it counts as a "stream" for royalty purposes. Accurate counting is a **financial requirement** -- errors mean paying artists incorrectly.

```python
class PlayEventProcessor:
    MINIMUM_PLAY_DURATION_MS = 30_000  # 30 seconds = counts as a stream

    def process_play_event(self, event):
        # Step 1: Validate the event
        if event.duration_played_ms < self.MINIMUM_PLAY_DURATION_MS:
            return  # Does not count as a stream

        # Step 2: Deduplicate (same user + same track + same timestamp)
        dedup_key = f"{event.user_id}:{event.track_id}:{event.timestamp}"
        if self.dedup_store.exists(dedup_key):
            return
        self.dedup_store.set(dedup_key, ttl=86400)

        # Step 3: Increment play count (real-time)
        self.play_count_db.increment(event.track_id)

        # Step 4: Write to royalty events table (append-only)
        self.royalty_events.append({
            "event_id": str(uuid4()),
            "track_id": event.track_id,
            "artist_id": event.artist_id,
            "user_id": event.user_id,
            "user_country": event.user_country,
            "user_tier": event.user_tier,
            "played_at": event.timestamp,
            "duration_ms": event.duration_played_ms,
        })


class RoyaltyCalculator:
    def calculate_monthly_royalties(self, month):
        # Spotify streamshare model:
        # Pool all subscription + ad revenue for the month
        # Divide by total streams
        # Each track gets: (its streams / total streams) * total revenue
        total_revenue = self.finance.get_monthly_revenue(month)
        total_streams = self.play_count_db.get_monthly_total(month)
        per_stream_rate = total_revenue / total_streams  # typically $0.003 - $0.005

        artist_payouts = {}
        for artist in self.catalog.get_all_artists():
            artist_streams = self.play_count_db.get_artist_monthly(artist.id, month)
            payout = artist_streams * per_stream_rate
            artist_payouts[artist.id] = payout

        return artist_payouts, per_stream_rate
