### Exactly-Once Processing with Kafka + Flink

```java
public class PlayEventFlinkJob {

    public static void main(String[] args) throws Exception {
        StreamExecutionEnvironment env = StreamExecutionEnvironment.getExecutionEnvironment();

        // Enable exactly-once checkpointing
        env.enableCheckpointing(60_000);
        env.getCheckpointConfig().setCheckpointingMode(CheckpointingMode.EXACTLY_ONCE);
        env.getCheckpointConfig().setMinPauseBetweenCheckpoints(30_000);

        KafkaSource<PlayEvent> source = KafkaSource.<PlayEvent>builder()
            .setBootstrapServers("kafka:9092")
            .setTopics("play-events")
            .setGroupId("play-event-processor")
            .setDeserializer(new PlayEventDeserializer())
            .build();

        DataStream<PlayEvent> events = env.fromSource(
            source, WatermarkStrategy.forBoundedOutOfOrderness(Duration.ofSeconds(30)),
            "play-events"
        );

        // Filter: only count plays >= 30 seconds
        DataStream<PlayEvent> validPlays = events
            .filter(e -> e.getDurationPlayedMs() >= 30_000);

        // Deduplicate using keyed state
        DataStream<PlayEvent> deduplicated = validPlays
            .keyBy(e -> e.getUserId() + ":" + e.getTrackId())
            .process(new DeduplicationFunction());

        deduplicated.addSink(new PlayCountSink());
        deduplicated.addSink(new RoyaltyEventSink());

        env.execute("Play Event Processor");
    }

    static class DeduplicationFunction
            extends KeyedProcessFunction<String, PlayEvent, PlayEvent> {
        private ValueState<Boolean> seen;

        @Override
        public void open(Configuration params) {
            ValueStateDescriptor<Boolean> desc =
                new ValueStateDescriptor<>("seen", Boolean.class);
            desc.enableTimeToLive(StateTtlConfig.newBuilder(Time.hours(24)).build());
            seen = getRuntimeContext().getState(desc);
        }

        @Override
        public void processElement(PlayEvent event, Context ctx, Collector<PlayEvent> out)
                throws Exception {
            if (seen.value() == null) {
                seen.update(true);
                out.collect(event);
            }
        }
    }
}
