```python
class PaymentOrchestrator:
    def process_charge(self, charge_request):
        # 1. Idempotency check
        cached = self.idempotency_store.get(charge_request.idempotency_key)
        if cached:
            return cached

        # 2. Tokenize card (if raw card number provided)
        token = self.tokenization.tokenize(charge_request.payment_method)

        # 3. Fraud check
        risk_score = self.fraud_service.evaluate(charge_request, token)
        if risk_score > 0.9:
            return ChargeResponse(status="blocked", reason="high_risk")
        if risk_score > 0.7:
            return ChargeResponse(status="requires_action", action="3ds_challenge")

        # 4. Authorize with card network
        auth_result = self.gateway.authorize(
            token=token,
            amount=charge_request.amount,
            currency=charge_request.currency,
            merchant_id=charge_request.merchant_id
        )

        # 5. Record in ledger (double-entry)
        if auth_result.approved:
            self.ledger.record_authorization(
                charge_id=auth_result.charge_id,
                amount=charge_request.amount,
                currency=charge_request.currency,
                merchant_id=charge_request.merchant_id
            )

        # 6. Emit event for webhooks
        self.event_bus.publish(
            "charge.authorized" if auth_result.approved else "charge.failed",
            auth_result
        )

        # 7. Cache response for idempotency
        response = ChargeResponse.from_auth(auth_result)
        self.idempotency_store.set(charge_request.idempotency_key, response, ttl=86400)

        return response
