```java
@Service
@Transactional
public class PaymentOrchestrator {

    @Autowired private IdempotencyStore idempotencyStore;
    @Autowired private TokenizationClient tokenization;
    @Autowired private FraudService fraudService;
    @Autowired private GatewayAdapter gateway;
    @Autowired private LedgerService ledger;
    @Autowired private EventBus eventBus;

    public ChargeResponse processCharge(ChargeRequest request) {
        // 1. Idempotency check
        Optional<ChargeResponse> cached = idempotencyStore.get(request.getIdempotencyKey());
        if (cached.isPresent()) return cached.get();

        // 2. Fraud scoring
        double riskScore = fraudService.evaluate(request);
        if (riskScore > 0.9) {
            return ChargeResponse.blocked("high_risk");
        }

        // 3. Authorize via card network
        AuthResult auth = gateway.authorize(
            request.getPaymentMethod(),
            request.getAmount(),
            request.getCurrency()
        );

        // 4. Record in financial ledger
        if (auth.isApproved()) {
            ledger.recordAuthorization(auth);
        }

        // 5. Publish event
        eventBus.publish(auth.isApproved()
            ? new ChargeAuthorizedEvent(auth)
            : new ChargeFailedEvent(auth));

        // 6. Store for idempotency
        ChargeResponse response = ChargeResponse.from(auth);
        idempotencyStore.set(request.getIdempotencyKey(), response);

        return response;
    }
}
