### Idempotency: The Most Critical Design Decision

In payment systems, network failures happen. If a charge request times out, did the charge succeed? Without idempotency, retrying could double-charge the customer.

```python
class IdempotencyMiddleware:
    def __init__(self, redis_client):
        self.redis = redis_client
        self.TTL = 86400  # 24 hours

    def process_request(self, idempotency_key, handler_fn):
        # Three scenarios:
        # 1. New request: process and cache result
        # 2. Duplicate request, original completed: return cached result
        # 3. Duplicate request, original in-progress: return 409 Conflict

        lock_key = f"idempotency:lock:{idempotency_key}"
        result_key = f"idempotency:result:{idempotency_key}"

        # Check for cached result (scenario 2)
        cached = self.redis.get(result_key)
        if cached:
            return json.loads(cached), 200

        # Try to acquire lock (scenario 1 vs 3)
        acquired = self.redis.set(lock_key, "processing", nx=True, ex=60)
        if not acquired:
            return {"error": "request_in_progress"}, 409

        try:
            result = handler_fn()
            self.redis.setex(result_key, self.TTL, json.dumps(result))
            return result, 200
        except Exception as e:
            self.redis.delete(lock_key)
            raise
        finally:
            self.redis.delete(lock_key)
```

```java
@Component
public class IdempotencyFilter implements HandlerInterceptor {

    @Autowired private RedisTemplate<String, String> redis;
    private static final long TTL_SECONDS = 86400;

    @Override
    public boolean preHandle(HttpServletRequest request, HttpServletResponse response,
                             Object handler) throws Exception {
        String idempotencyKey = request.getHeader("Idempotency-Key");
        if (idempotencyKey == null) return true;

        String resultKey = "idempotency:result:" + idempotencyKey;
        String cached = redis.opsForValue().get(resultKey);

        if (cached != null) {
            response.setContentType("application/json");
            response.getWriter().write(cached);
            response.setStatus(200);
            return false;
        }

        String lockKey = "idempotency:lock:" + idempotencyKey;
        Boolean acquired = redis.opsForValue()
            .setIfAbsent(lockKey, "processing", Duration.ofSeconds(60));

        if (!Boolean.TRUE.equals(acquired)) {
            response.setStatus(409);
            response.getWriter().write("{"error":"request_in_progress"}");
            return false;
        }

        request.setAttribute("idempotency_key", idempotencyKey);
        return true;
    }
}
