class WebhookDeliveryService:
    RETRY_INTERVALS = [60, 300, 1800, 7200, 28800, 86400]

    def deliver(self, event, endpoint):
        payload = json.dumps(event.to_dict())

        timestamp = int(time.time())
        signature = self.sign(timestamp, payload, endpoint.secret)

        headers = {
            "Content-Type": "application/json",
            "Stripe-Signature": f"t={timestamp},v1={signature}",
        }

        try:
            response = requests.post(
                endpoint.url, data=payload, headers=headers, timeout=30
            )
            if response.status_code < 300:
                self.mark_delivered(event.id, endpoint.id)
            else:
                self.schedule_retry(event, endpoint, attempt=1)
        except requests.Timeout:
            self.schedule_retry(event, endpoint, attempt=1)

    def sign(self, timestamp, payload, secret):
        signed_payload = f"{timestamp}.{payload}"
        return hmac.new(
            secret.encode(), signed_payload.encode(), hashlib.sha256
        ).hexdigest()
