### Payment State Machine Implementation

```python
from enum import Enum

class ChargeStatus(Enum):
    CREATED = "created"
    PROCESSING = "processing"
    AUTHORIZED = "authorized"
    CAPTURED = "captured"
    SETTLED = "settled"
    FAILED = "failed"
    CANCELLED = "cancelled"
    REFUNDED = "refunded"
    PARTIALLY_REFUNDED = "partially_refunded"
    DISPUTED = "disputed"

TRANSITIONS = {
    ChargeStatus.CREATED: [ChargeStatus.PROCESSING],
    ChargeStatus.PROCESSING: [ChargeStatus.AUTHORIZED, ChargeStatus.FAILED],
    ChargeStatus.AUTHORIZED: [ChargeStatus.CAPTURED, ChargeStatus.CANCELLED],
    ChargeStatus.CAPTURED: [
        ChargeStatus.SETTLED,
        ChargeStatus.REFUNDED,
        ChargeStatus.PARTIALLY_REFUNDED,
        ChargeStatus.DISPUTED
    ],
    ChargeStatus.PARTIALLY_REFUNDED: [
        ChargeStatus.SETTLED,
        ChargeStatus.REFUNDED,
        ChargeStatus.PARTIALLY_REFUNDED
    ],
}

class PaymentStateMachine:
    def transition(self, charge, new_status):
        current = ChargeStatus(charge.status)
        valid_next = TRANSITIONS.get(current, [])

        if new_status not in valid_next:
            raise InvalidTransitionError(
                f"Cannot transition from {current.value} to {new_status.value}. "
                f"Valid transitions: {[s.value for s in valid_next]}"
            )

        with self.db.transaction():
            old_status = charge.status
            charge.status = new_status.value
            charge.updated_at = datetime.utcnow()
            self.db.save(charge)

            self.audit_log.append({
                "charge_id": charge.id,
                "from_status": old_status,
                "to_status": new_status.value,
                "timestamp": datetime.utcnow(),
                "actor": self.current_actor,
            })
```

### Saga Pattern for Multi-Step Operations

A payment involves multiple services that must succeed or roll back together. The **saga pattern** coordinates this without distributed transactions.

```python
class ChargeSaga:
    def execute(self, charge_request):
        steps = [
            SagaStep(
                action=lambda: self.fraud_service.evaluate(charge_request),
                compensation=None
            ),
            SagaStep(
                action=lambda: self.gateway.authorize(charge_request),
                compensation=lambda auth: self.gateway.void(auth.id)
            ),
            SagaStep(
                action=lambda: self.ledger.record_authorization(charge_request),
                compensation=lambda: self.ledger.reverse_authorization(charge_request)
            ),
            SagaStep(
                action=lambda: self.event_bus.publish("charge.authorized", charge_request),
                compensation=None  # events are facts, no undo needed
            ),
        ]

        completed = []
        try:
            for step in steps:
                result = step.action()
                completed.append((step, result))
        except Exception as e:
            for step, result in reversed(completed):
                if step.compensation:
                    try:
                        step.compensation(result) if result else step.compensation()
                    except Exception as comp_error:
                        self.alert_service.critical(
                            f"Compensation failed for charge {charge_request.id}: {comp_error}"
                        )
            raise
```

```java
@Service
public class ChargeSagaOrchestrator {

    @Autowired private FraudService fraudService;
    @Autowired private GatewayAdapter gateway;
    @Autowired private LedgerService ledger;
    @Autowired private EventBus eventBus;

    public ChargeResult executeCharge(ChargeRequest request) {
        AuthorizationResult auth = null;
        boolean ledgerRecorded = false;

        try {
            // Step 1: Fraud check
            RiskAssessment risk = fraudService.evaluate(request);
            if (risk.isBlocked()) {
                return ChargeResult.declined("fraud_detected");
            }

            // Step 2: Authorize with card network
            auth = gateway.authorize(request);
            if (!auth.isApproved()) {
                return ChargeResult.declined(auth.getDeclineCode());
            }

            // Step 3: Record in ledger
            ledger.recordAuthorization(auth);
            ledgerRecorded = true;

            // Step 4: Publish event
            eventBus.publish(new ChargeAuthorizedEvent(auth));

            return ChargeResult.success(auth);

        } catch (Exception e) {
            if (ledgerRecorded) {
                ledger.reverseAuthorization(auth);
            }
            if (auth != null && auth.isApproved()) {
                gateway.voidAuthorization(auth.getId());
            }
            throw new PaymentProcessingException("Charge saga failed", e);
        }
    }
}
```

### Handling Edge Cases

| Scenario | Handling Strategy |
|----------|------------------|
| **Timeout during authorization** | Mark as "unknown", query gateway for status after 30s |
| **Partial capture** | Authorize $100, capture $75, release remaining $25 hold |
| **Partial refund** | Refund $30 of $100 charge; update amount_refunded |
| **Double refund attempt** | Idempotency key prevents; check amount_refunded + new_refund <= amount_captured |
| **Dispute received** | Freeze merchant payout, request evidence, submit to card network |
| **Authorization expires** | Authorizations expire after 7 days; re-authorize if needed |

### Retry with Exponential Backoff and Circuit Breaker

```python
class GatewayClient:
    def __init__(self):
        self.circuit_breaker = CircuitBreaker(
            failure_threshold=5,
            recovery_timeout=30,
            expected_exceptions=[GatewayTimeoutError]
        )

    def authorize(self, request):
        if self.circuit_breaker.is_open():
            raise CircuitOpenError("Gateway circuit breaker is open")

        try:
            response = self.http_client.post(
                f"{self.gateway_url}/authorize",
                json=request.to_dict(),
                timeout=5
            )
            self.circuit_breaker.record_success()
            return AuthResult.from_response(response)
        except TimeoutError:
            self.circuit_breaker.record_failure()
            raise GatewayTimeoutError("Authorization timed out")
```

