### Reconciliation: Ensuring Financial Accuracy

Reconciliation is the process of comparing your internal ledger with external sources (bank statements, card network settlement files) to ensure every dollar is accounted for.

```python
class ReconciliationEngine:
    def run_daily_reconciliation(self, date):
        # 1. Fetch internal records
        internal_charges = self.ledger.get_charges_for_date(date)
        internal_refunds = self.ledger.get_refunds_for_date(date)

        # 2. Fetch external records
        bank_settlements = self.bank_client.get_settlement_file(date)
        network_reports = self.card_network.get_daily_report(date)

        # 3. Match records
        results = ReconciliationResults()

        for charge in internal_charges:
            bank_match = self._find_match(charge, bank_settlements)
            network_match = self._find_match(charge, network_reports)

            if bank_match and network_match:
                if charge.amount == bank_match.amount == network_match.amount:
                    results.reconciled.append(charge.id)
                else:
                    results.amount_mismatch.append({
                        "charge_id": charge.id,
                        "internal": charge.amount,
                        "bank": bank_match.amount,
                        "network": network_match.amount,
                    })
            elif not bank_match:
                results.missing_from_bank.append(charge.id)
            elif not network_match:
                results.missing_from_network.append(charge.id)

        # 4. Auto-resolve known patterns
        for mismatch in results.amount_mismatch:
            if self._is_currency_rounding(mismatch):
                results.auto_resolved.append(mismatch)
            elif self._is_timing_difference(mismatch):
                results.deferred_to_tomorrow.append(mismatch)

        # 5. Remaining discrepancies go to manual review
        results.manual_review = [
            m for m in results.amount_mismatch
            if m not in results.auto_resolved and m not in results.deferred_to_tomorrow
        ]

        return results

    def _is_currency_rounding(self, mismatch):
        amounts = [mismatch["internal"], mismatch["bank"], mismatch["network"]]
        return max(amounts) - min(amounts) <= 2

    def _is_timing_difference(self, mismatch):
        charge = self.ledger.get_charge(mismatch["charge_id"])
        return charge.created_at.hour >= 23
```

```java
@Service
public class ReconciliationService {

    @Autowired private LedgerRepository ledger;
    @Autowired private BankSettlementClient bankClient;
    @Autowired private AlertService alertService;

    @Scheduled(cron = "0 6 * * *")
    public void runDailyReconciliation() {
        LocalDate yesterday = LocalDate.now().minusDays(1);
        ReconciliationReport report = reconcile(yesterday);

        double discrepancyRate = (double) report.getDiscrepancies().size()
            / report.getTotalTransactions();

        if (discrepancyRate > 0.001) {
            alertService.page("reconciliation_high_discrepancy",
                String.format("Discrepancy rate %.3f%% for %s (%d/%d transactions)",
                    discrepancyRate * 100, yesterday,
                    report.getDiscrepancies().size(),
                    report.getTotalTransactions()));
        }

        reconciliationReportRepo.save(report);
    }

    public ReconciliationReport reconcile(LocalDate date) {
        List<LedgerEntry> internal = ledger.getEntriesForDate(date);
        List<BankSettlement> bankRecords = bankClient.getSettlement(date);

        ReconciliationReport report = new ReconciliationReport(date);
        Map<String, BankSettlement> bankIndex = bankRecords.stream()
            .collect(Collectors.toMap(
                BankSettlement::getTransactionRef, Function.identity()));

        for (LedgerEntry entry : internal) {
            BankSettlement match = bankIndex.get(entry.getTransactionId().toString());
            if (match == null) {
                report.addDiscrepancy(new Discrepancy(
                    entry.getTransactionId(), "missing_from_bank",
                    entry.getAmount(), 0));
            } else if (entry.getAmount() != match.getAmount()) {
                report.addDiscrepancy(new Discrepancy(
                    entry.getTransactionId(), "amount_mismatch",
                    entry.getAmount(), match.getAmount()));
                bankIndex.remove(entry.getTransactionId().toString());
            } else {
                report.addReconciled(entry.getTransactionId());
                bankIndex.remove(entry.getTransactionId().toString());
            }
        }

        for (BankSettlement orphan : bankIndex.values()) {
            report.addDiscrepancy(new Discrepancy(
                null, "missing_from_internal", 0, orphan.getAmount()));
        }

        return report;
    }
}
